#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int M, N, J;
        scanf("%d %d %d", &M, &N, &J);
        int hands[N][M];
        for (int i = 0; i < N; i++) {
            char hex[100];
            scanf("%s", hex);
            int len = strlen(hex);
            for (int j = 0; j < len; j++) {
                int val = (hex[j] >= '0' && hex[j] <= '9') ? hex[j] - '0' : hex[j] - 'a' + 10;
                for (int k = 0; k < 4; k++) {
                    if (val & (1 << k)) {
                        hands[i][k + j * 4] = 1;
                    }
                }
            }
        }
        for (int i = 0; i < J; i++) {
            char hex[100];
            scanf("%s", hex);
            int len = strlen(hex);
            int recipe[M];
            memset(recipe, 0, sizeof(recipe));
            for (int j = 0; j < len; j++) {
                int val = (hex[j] >= '0' && hex[j] <= '9') ? hex[j] - '0' : hex[j] - 'a' + 10;
                for (int k = 0; k < 4; k++) {
                    if (val & (1 << k)) {
                        recipe[k + j * 4] = 1;
                    }
                }
            }
            int base = 0;
            for (int j = 0; j < M; j++) {
                int found = 0;
                for (int k = 0; k < N; k++) {
                    if (hands[k][j]) {
                        int hasOther = 0;
                        for (int l = 0; l < M; l++) {
                            if (l != j && hands[k][l] && recipe[l]) {
                                hasOther = 1;
                                break;
                            }
                        }
                        if (!hasOther) {
                            found = 1;
                            break;
                        }
                    }
                }
                if (!found) {
                    base++;
                }
            }
            printf("%d\n", base);
        }
    }
    return 0;
}

